import{_ as a,n as e,p as l,Y as o}from"./chunks/framework.KP8KjELV.js";const p=JSON.parse('{"title":"前端性能优化","description":"前端性能优化","frontmatter":{"date":"2022-02-26T00:00:00.000Z","head":[["meta",{"name":"description","content":"前端性能优化"}],["meta",{"name":"keywords","content":"前端,前端优化,前端性能优化,前端首屏优化,首屏加载优化,前端性能"}]]},"headers":[],"relativePath":"Stack/Deploy/前端性能优化.md","filePath":"Stack/Deploy/前端性能优化.md","lastUpdated":1703840066000}'),t={name:"Stack/Deploy/前端性能优化.md"},i=o('<h1 id="前端性能优化" tabindex="-1">前端性能优化 <a class="header-anchor" href="#前端性能优化" aria-label="Permalink to &quot;前端性能优化&quot;">​</a></h1><h2 id="网络传输性能优化" tabindex="-1">网络传输性能优化 <a class="header-anchor" href="#网络传输性能优化" aria-label="Permalink to &quot;网络传输性能优化&quot;">​</a></h2><h3 id="_1-使用-http2" tabindex="-1">1. 使用 HTTP2 <a class="header-anchor" href="#_1-使用-http2" aria-label="Permalink to &quot;1. 使用 HTTP2&quot;">​</a></h3><blockquote><p>HTTP2 相对于 HTTP1 进行了下面的优化：</p></blockquote><ul><li>二进制分帧层</li><li>多路复用</li><li>首部压缩</li><li>请求优先级</li><li>服务器推送</li><li>流量控制</li></ul><h3 id="_2-资源打包压缩" tabindex="-1">2. 资源打包压缩 <a class="header-anchor" href="#_2-资源打包压缩" aria-label="Permalink to &quot;2. 资源打包压缩&quot;">​</a></h3><blockquote><p>资源打包压缩主要是通过 webpack 压缩以下内容：</p></blockquote><ul><li>压缩 JS 代码：通过 webpack 的 production 模式压缩 JS 代码。</li><li>压缩 HTML 代码：使用 html-webpack-plugin 的 minify 进行压缩。</li><li>压缩 CSS 代码：使用 cssnano 压缩 css，在 postcss.config.js 中进行配置。</li></ul><h3 id="_3-图片资源优化" tabindex="-1">3. 图片资源优化 <a class="header-anchor" href="#_3-图片资源优化" aria-label="Permalink to &quot;3. 图片资源优化&quot;">​</a></h3><blockquote><p>在网络传输中真正占用大量网络资源的不是文件而是图片，如果对图片进行了优化，可以看到立竿见影的效果。主要优化措施如下：</p></blockquote><ul><li>在 html 中尽量不要放图片。</li><li>使用雪碧图：雪碧图可以减少请求的次数。</li><li>使用字体图标：字体图片能够像图片一样工作，但是资源占用和图片请求比起来小很多。</li><li>使用 webp：webp 格式的图片相对根据国家节省网络带宽。</li></ul><h3 id="_4-使用-cdn" tabindex="-1">4. 使用 CDN <a class="header-anchor" href="#_4-使用-cdn" aria-label="Permalink to &quot;4. 使用 CDN&quot;">​</a></h3><blockquote><p>CDN 指的是在网络不同地点部署节点服务器，将源站内容分发至所有 CDN 节点，使得用户可以就近获得所需内容。CDN 提高了网站的响应速度、降低了延迟。</p></blockquote><h3 id="_5-使用预加载" tabindex="-1">5. 使用预加载 <a class="header-anchor" href="#_5-使用预加载" aria-label="Permalink to &quot;5. 使用预加载&quot;">​</a></h3><blockquote><p>当一个页面加载时，可能会加载很多第三方资源，但是这些资源的优先级是不同的，一些重要资源需要提前进行获取，因此我们可以使用 link 标签来进行 DNS 预解析、预加载、预渲染来管理页面资源的加载。</p></blockquote><h3 id="_6-减少-dns-查找" tabindex="-1">6. 减少 DNS 查找 <a class="header-anchor" href="#_6-减少-dns-查找" aria-label="Permalink to &quot;6. 减少 DNS 查找&quot;">​</a></h3><blockquote><p>尽量将资源放在同一域名下面，因为域名越少，DNS 查询就会越少。</p></blockquote><h3 id="_7-发送请求时使用防抖和节流策略" tabindex="-1">7. 发送请求时使用防抖和节流策略 <a class="header-anchor" href="#_7-发送请求时使用防抖和节流策略" aria-label="Permalink to &quot;7. 发送请求时使用防抖和节流策略&quot;">​</a></h3><blockquote><p>防抖节流可以避免短时间内发送过多的重复请求。</p></blockquote><h2 id="页面渲染性能优化" tabindex="-1">页面渲染性能优化 <a class="header-anchor" href="#页面渲染性能优化" aria-label="Permalink to &quot;页面渲染性能优化&quot;">​</a></h2><h3 id="_1-减少重排和重绘的发生" tabindex="-1">1. 减少重排和重绘的发生 <a class="header-anchor" href="#_1-减少重排和重绘的发生" aria-label="Permalink to &quot;1. 减少重排和重绘的发生&quot;">​</a></h3><ul><li>重排：指的是元素布局发生修改，导致页面重新排列。</li><li>重绘：所有对元素的视觉表现属性的修改，都会引发重绘。</li></ul><blockquote><p>重排和重绘都会影响性能，要想提高网页性能尽可能降低重排和重绘的频率。重排是由 CPU 处理的，而重绘是由 GPU 处理的，GPU 的处理效率要相对更高，重排一定发生重绘，但是重绘不一定引起重排，所以要尽可能的降低重排和重绘的发生。</p></blockquote><h3 id="_2-dom-元素离线更新" tabindex="-1">2. DOM 元素离线更新 <a class="header-anchor" href="#_2-dom-元素离线更新" aria-label="Permalink to &quot;2. DOM 元素离线更新&quot;">​</a></h3><blockquote><p>当对 DOM 元素进行操作的时候，尽量使用 documentFragment 对象进行离线操作，待元素组装完成之后再一次插入页面。</p></blockquote><h3 id="_3-避免-css、js-阻塞" tabindex="-1">3. 避免 CSS、JS 阻塞 <a class="header-anchor" href="#_3-避免-css、js-阻塞" aria-label="Permalink to &quot;3. 避免 CSS、JS 阻塞&quot;">​</a></h3><blockquote><p>CSS 资源优于 JS 资源的引入，JS 应当尽量少影响 DOM 的构建。</p></blockquote><h2 id="经典问题" tabindex="-1">经典问题 <a class="header-anchor" href="#经典问题" aria-label="Permalink to &quot;经典问题&quot;">​</a></h2><h3 id="rq1-首屏加载如何优化" tabindex="-1">RQ1：首屏加载如何优化？ <a class="header-anchor" href="#rq1-首屏加载如何优化" aria-label="Permalink to &quot;RQ1：首屏加载如何优化？&quot;">​</a></h3><blockquote><p>主要方法包括以下步骤：</p></blockquote><ol><li>动态加载路由</li></ol><blockquote><p>配置路由的时候，以函数的形式加载路由，只有在解析给定的路由时，才会加载路由。</p></blockquote><ol><li>合理使用缓存</li></ol><blockquote><p>设置强缓存、协商缓存、localstorage 等。</p></blockquote><ol><li>UI 框架按需加载</li></ol><blockquote><p>不要引入整个 UI 库，尽量进行按需加载。</p></blockquote><ol><li>避免重复加载组件</li></ol><blockquote><p>可以使用 webpack 将多次使用的包抽离出来，放入公共依赖文件，避免重复加载组件。</p></blockquote><ol><li>压缩图片资源</li></ol><blockquote><p>雪碧图、字体图标、webp 等。</p></blockquote><ol><li>开启 Gzip 压缩</li><li>使用 SSR 服务端渲染</li></ol><blockquote><p>组件或页面通过服务器生成 html 字符串，再发送到浏览器。</p></blockquote>',42),c=[i];function r(h,n,u,d,b,s){return e(),l("div",null,c)}const k=a(t,[["render",r]]);export{p as __pageData,k as default};
